from PhseXlib.addres import addres_transformer,is_address

def memory_usage_check(func):
    def warpper(*args):
        # 遍历参数并检测地址
        for arg in args:
            addr_route = addres_transformer(arg)
            if is_address(addr_route):
                pass
            else:
                pass
        # 执行原函数
        return func(*args)
    return warpper